import uuid
from dataclasses import dataclass, field
from typing import List, Optional

@dataclass
class TurnCost:
    turn_index: int
    model_id: str
    input_tokens: int
    output_tokens: int
    cache_read_tokens: int
    input_price_per_1m: float
    output_price_per_1m: float
    cache_price_per_1m: float

    @property
    def cost_usd(self) -> float:
        return (
            self.input_tokens / 1_000_000 * self.input_price_per_1m
            + self.output_tokens / 1_000_000 * self.output_price_per_1m
            + self.cache_read_tokens / 1_000_000 * self.cache_price_per_1m
        )

@dataclass
class ConversationCostRecord:
    conversation_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    team_id: str = ""
    workflow_type: str = ""
    turns: List[TurnCost] = field(default_factory=list)

    def add_turn(self, turn: TurnCost) -> None:
        self.turns.append(turn)

    @property
    def total_cost_usd(self) -> float:
        return sum(t.cost_usd for t in self.turns)

    @property
    def turn_count(self) -> int:
        return len(self.turns)

    @property
    def total_input_tokens(self) -> int:
        return sum(t.input_tokens for t in self.turns)

    def summary(self) -> dict:
        return {
            "conversation_id": self.conversation_id,
            "total_cost_usd": round(self.total_cost_usd, 6),
            "turn_count": self.turn_count,
            "total_input_tokens": self.total_input_tokens,
            "cost_per_turn_usd": round(self.total_cost_usd / max(self.turn_count, 1), 6),
        }

from dataclasses import dataclass, field
from collections import defaultdict
from typing import Dict, List

@dataclass
class TaskCostRecord:
    task_type: str           # e.g. "web_search", "code_generation", "classification"
    conversation_id: str
    agent_id: str
    input_tokens: int
    output_tokens: int
    price_per_1m_input: float
    price_per_1m_output: float

    @property
    def cost_usd(self) -> float:
        return (self.input_tokens / 1_000_000 * self.price_per_1m_input
                + self.output_tokens / 1_000_000 * self.price_per_1m_output)

def aggregate_cost_per_task(records: List[TaskCostRecord]) -> Dict[str, dict]:
    """
    Aggregate task costs by type to compute average cost per task type.
    Useful for identifying which agent actions drive the most spend.
    """
    buckets: Dict[str, List[float]] = defaultdict(list)
    for r in records:
        buckets[r.task_type].append(r.cost_usd)
    return {
        task_type: {
            "count": len(costs),
            "avg_cost_usd": sum(costs) / len(costs),
            "total_cost_usd": sum(costs),
            "p95_cost_usd": sorted(costs)[int(0.95 * len(costs))],
        }
        for task_type, costs in buckets.items()
    }

from dataclasses import dataclass

@dataclass
class CPAUMetrics:
    monthly_ai_spend_usd: float
    monthly_active_users: int             # users who made at least one AI request
    monthly_revenue_per_user_usd: float   # average revenue per MAU (from finance)
    target_ai_cost_as_pct_of_revenue: float = 0.15  # 15% as target

    @property
    def cpau(self) -> float:
        return self.monthly_ai_spend_usd / max(self.monthly_active_users, 1)

    @property
    def ai_pct_of_revenue(self) -> float:
        return self.cpau / self.monthly_revenue_per_user_usd

    @property
    def is_within_target(self) -> bool:
        return self.ai_pct_of_revenue <= self.target_ai_cost_as_pct_of_revenue

    def summary(self) -> dict:
        return {
            "cpau_usd": round(self.cpau, 4),
            "ai_pct_of_revenue": f"{self.ai_pct_of_revenue:.1%}",
            "target_pct": f"{self.target_ai_cost_as_pct_of_revenue:.1%}",
            "within_target": self.is_within_target,
        }

# Example
metrics = CPAUMetrics(
    monthly_ai_spend_usd=45_000,
    monthly_active_users=12_000,
    monthly_revenue_per_user_usd=29.0,
)
print(metrics.summary())
# {'cpau_usd': 3.75, 'ai_pct_of_revenue': '12.9%', 'target_pct': '15.0%', 'within_target': True}
